#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        scanf("%lld", &n);
        if (n % 2 == 0) {
            printf("true\n");
        } else {
            printf("false\n");
        }
    }
    return 0;
}

